import{_ as t,o as e,c as a,a2 as i}from"./chunks/framework.CXrMbE71.js";const m=JSON.parse('{"title":"第五卷：终端的艺术与人民的起义——硬件巨头与开源叛逆者","description":"","frontmatter":{},"headers":[],"relativePath":"vol5.md","filePath":"vol5.md"}'),r={name:"vol5.md"};function n(s,o,l,p,d,g){return e(),a("div",null,[...o[0]||(o[0]=[i('<h1 id="第五卷-终端的艺术与人民的起义——硬件巨头与开源叛逆者" tabindex="-1">第五卷：终端的艺术与人民的起义——硬件巨头与开源叛逆者 <a class="header-anchor" href="#第五卷-终端的艺术与人民的起义——硬件巨头与开源叛逆者" aria-label="Permalink to &quot;第五卷：终端的艺术与人民的起义——硬件巨头与开源叛逆者&quot;">​</a></h1><blockquote><p><em>&quot;当 BAT 这种软件巨头在云端打得不可开交时，掌握着中国千万台物理终端的硬件巨头，以及 GitHub 上的草根极客们，正在用一种更硬核、更底层的玩法，掀翻巨头们铺设的云端盛宴。&quot;</em></p></blockquote><hr><h2 id="📖-第一节-基础简介与生态位" tabindex="-1">📖 第一节：基础简介与生态位 <a class="header-anchor" href="#📖-第一节-基础简介与生态位" aria-label="Permalink to &quot;📖 第一节：基础简介与生态位&quot;">​</a></h2><p><strong>企业背景</strong>：由小米领衔的硬件巨头，以及 StepFun (阶跃星辰)、LangGenius (Dify) 等生猛的 AI 新势力阵营。 <strong>核心战略</strong>：避开纯软生态的内卷，将大模型的能力下发到“万物互联 (AIoT)”与开源社区基础设施中。做大厂不愿意做脏活累活的“底层接线员”。</p><hr><p><img src="https://github.com/XiaoMi.png" alt="Xiaomi Logo"></p><h2 id="_2-小米-xiaomi-的极客反扑-mimo-code-的终端魔法" tabindex="-1">2. 小米 (Xiaomi) 的极客反扑：MiMo Code 的终端魔法 <a class="header-anchor" href="#_2-小米-xiaomi-的极客反扑-mimo-code-的终端魔法" aria-label="Permalink to &quot;2. 小米 (Xiaomi) 的极客反扑：MiMo Code 的终端魔法&quot;">​</a></h2><p>很难想象，一家以做手机和智能家居闻名的硬件大厂，在 2026 年交出了整个国内开源社区最优雅的一款命令行 Agent——<strong>MiMo Code</strong> (<code>@xiaomi-mimo/cli</code>)。</p><h3 id="tui-终端用户界面-任务树-把命令行画成艺术品" tabindex="-1">TUI (终端用户界面) 任务树：把命令行画成艺术品 <a class="header-anchor" href="#tui-终端用户界面-任务树-把命令行画成艺术品" aria-label="Permalink to &quot;TUI (终端用户界面) 任务树：把命令行画成艺术品&quot;">​</a></h3><p>在绝大多数人的印象里，命令行就是黑底白字的字符串滚动。 但小米的工程师认为，长线任务如果在纯文本终端里跑，一旦出错，人类根本无法追踪上下文。</p><p>于是，MiMo Code 引入了极其华丽的 <strong>交互式终端 TUI (Terminal UI)</strong>。 当 MiMo Code 开始重构你的项目时，终端会分裂成几个板块：左侧是实时的树状图（Task Trees），展示 Agent 规划的思维节点；右侧是流式代码对比（Diff）；底部则是 Agent 当前正在执行的 Shell 进度条。</p><h3 id="跨会话持久记忆-persistent-memory" tabindex="-1">跨会话持久记忆 (Persistent Memory) <a class="header-anchor" href="#跨会话持久记忆-persistent-memory" aria-label="Permalink to &quot;跨会话持久记忆 (Persistent Memory)&quot;">​</a></h3><p>MiMo Code 引入了极具硬件厂商思维的“存档”机制。 它会在你的项目深处隐藏一个轻量级的 <code>.mimo-vault</code>。今天下班前 Agent 只写了一半的复杂重构，明天重新唤醒它能瞬间从断点读取所有上下文和中间态变量，继续接着写，这被称为<strong>跨会话的持久化记忆</strong>。</p><hr><h2 id="_3-阶跃星辰-stepfun-多模态桌面的-暗中观察者" tabindex="-1">3. 阶跃星辰 (StepFun)：多模态桌面的“暗中观察者” <a class="header-anchor" href="#_3-阶跃星辰-stepfun-多模态桌面的-暗中观察者" aria-label="Permalink to &quot;3. 阶跃星辰 (StepFun)：多模态桌面的“暗中观察者”&quot;">​</a></h2><p><img src="https://images.seeklogo.com/logo-png/61/1/stepfun-logo-png_seeklogo-611698.png" alt="StepFun Logo"></p><p><strong>阶跃星辰 (StepFun)</strong> 走的是一条极其激进的路线。他们在 2026 年初推出的 <strong>StepClaw 桌面伴侣</strong>，打破了文字交互的桎梏。</p><h3 id="_7x24-小时的全双工视听感知" tabindex="-1">7x24 小时的全双工视听感知 <a class="header-anchor" href="#_7x24-小时的全双工视听感知" aria-label="Permalink to &quot;7x24 小时的全双工视听感知&quot;">​</a></h3><p>StepClaw 并不是一个需要你主动去“提问”的对话框。它是一个潜伏在后台的多模态 Agent (Leap AI Worker)。 它通过高度优化的底层引擎，极低功耗地监听系统剪贴板，甚至是屏幕的实时变化流。当你在看一份复杂的财报时，不需要复制粘贴，只需要戴着耳机问一句：“这段为啥跑不通？”，StepClaw 会直接通过全双工语音告诉你答案。</p><hr><h2 id="_4-草根的起义-开源界的手搓-antigravity" tabindex="-1">4. 草根的起义：开源界的手搓 Antigravity <a class="header-anchor" href="#_4-草根的起义-开源界的手搓-antigravity" aria-label="Permalink to &quot;4. 草根的起义：开源界的手搓 Antigravity&quot;">​</a></h2><p>对于真正硬核的极客来说，用大厂的现成工具永远是不自由的。他们要在本地手搓出属于自己的终极武器。</p><h3 id="dify-的终极进化-桌面编译器-desktop-compiler" tabindex="-1">Dify 的终极进化：桌面编译器 (Desktop Compiler) <a class="header-anchor" href="#dify-的终极进化-桌面编译器-desktop-compiler" aria-label="Permalink to &quot;Dify 的终极进化：桌面编译器 (Desktop Compiler)&quot;">​</a></h3><p><img src="https://github.com/langgenius/dify/raw/main/images/GitHub_README_if.png" alt="Dify GitHub README Diagram"></p><p><strong>Dify</strong> 曾经是一个拖拽画图的网页端应用。但在 2026 年，Dify 抛出了它的王炸——<strong>Dify Desktop Compiler</strong>。 这代表着，极客们可以在 Dify 的画布里，用拖拽节点的方式画出一个无比复杂的 Agent 工作流。然后，点击“导出”。 Dify 会自动帮你把这个工作流打包编译成一个独立的、不依赖大厂云环境的 Windows <code>.exe</code> 或 Mac <code>.dmg</code> 桌面端应用程序。极客们彻底实现了私人 Agent App 的量产。</p><h3 id="nanobot-tauri-的性能奇迹" tabindex="-1">Nanobot：Tauri 的性能奇迹 <a class="header-anchor" href="#nanobot-tauri-的性能奇迹" aria-label="Permalink to &quot;Nanobot：Tauri 的性能奇迹&quot;">​</a></h3><p><img src="https://avatars.githubusercontent.com/u/38827725?v=4" alt="Nanobot Logo"></p><p>在桌面端，Electron 架构因为极其占用内存而饱受诟病。 开源社区的叛逆之作 <strong>Nanobot</strong> 横空出世。它采用 Rust 语言底层的 <strong>Tauri 框架</strong> 重写了整个 Agent 桌面端 UI。</p><p>整个控制面板的内存占用被强行压缩到了 <strong>不足 40MB</strong>！ 在这个极度纯净的 UI 里，你可以随心所欲地控制你本机的开源大模型，分配 Agent 内存，查看实时抓取日志。</p><blockquote><p><em>&quot;开源社区用几十 M 的超小软件和几行配置代码，给了那些动辄占用几个 G 内存的大厂软件一记响亮的耳光。真正的自由，永远在本地。&quot;</em></p></blockquote>',31)])])}const c=t(r,[["render",n]]);export{m as __pageData,c as default};
